import { WorldTrackingAnchorGroup } from './worldtrackinganchorgroup.js';
/**
 * A THREE.Group which attaches content to a point on the ground as it moves around in the camera view.
 * @see https://docs.zap.works/universal-ar/web-libraries/threejs/world-tracking/
 */
export class GroundAnchorGroup extends WorldTrackingAnchorGroup {
    /**
     * Constructs a new GroundAnchorGroup.
     * @param camera - A ZapparThree.Camera.
     * @param worldTracker - The world tracker which will be used.
     */
    constructor(camera, worldTracker) {
        super(camera, worldTracker);
        this.anchor = worldTracker.groundAnchor;
    }
}
